import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { EnvService } from "src/app/core/services/env.service";
import { IClientType } from "src/app/views/Models/Client/ClientType";
import { FormStatus } from "src/app/views/Models/forms/formStatus";
import {
  ClientByOfficer,
  IOfficer,
} from "src/app/views/Models/Officer/Officer";
import { ReferencesService } from "src/app/core/services/references.service";
import { pagingService } from "src/app/core/services/paging.service";
import { sortingService } from "src/app/core/services/sorting.service";
@Component({
  selector: "app-client-change-officer",
  templateUrl: "./client-change-officer.page.html",
  styleUrls: ["./client-change-officer.page.scss"],
})
export class ClientChangeOfficerPage implements OnInit {
  [x: string]: any;
  filterForm: FormGroup;
  pageSize: number;
  pageSizeForSupervised: number;
  sortingIconClass: string;
  sortingIconParam: string;
  page = 1;
  resultsCount;
  totalPages = 1;
  resultOfInsert;
  pageForSupervised = 1;
  constructor(
    private ReferencesService: ReferencesService,
    private formBuilder: FormBuilder,
    private env: EnvService,
    public pagingService: pagingService,
    private alertService: AlertService,
    private http: HttpClient,
    private sortingService: sortingService
  ) {}
  showLoader: boolean = false;
  filterFormStatus: FormStatus = { valid: false, visible: true };
  CLModelResponse: IClientType[];
  Officer: IOfficer[];
  ClientByOfficer: ClientByOfficer[] = [];
  officerModelResponse: IOfficer[];
  ngOnInit() {
    this.Load();
    this.pageSize = this.pagingService.getPageSizeFromLocalStorage();
    this.pageSizeForSupervised =
      this.pagingService.getPageSizeFromLocalStorage();
    this.filterForm = this.formBuilder.group({
      old: ["", [Validators.required]],
      ClientType: ["", [Validators.required]],
      ClientStatus: ["", [Validators.required]],
    });
    this.OfficerForm = this.formBuilder.group({
      OfficerAllActive: ["", [Validators.required]],
    });
  }
  async Load() {
    this.filterFormStatus.valid = true;
    this.filterFormStatus.visible = true;
    this.CLModelResponse = await this.ReferencesService.GetClientTypes();
    this.officerModelResponse = await this.ReferencesService.GetOfficersAll();
  }
  async filterSearchBtn() {
    if (this.filterForm.valid) {
      this.showLoader = true;
      this.http
        .get<ClientByOfficer[]>(
          `${this.env.API_URL}api/Officer/GetClientByOfficer?officer_key=${this.filterForm.value.old}&client_type_code=${this.filterForm.value.ClientType}&client_status=${this.filterForm.value.ClientStatus}`
        )
        .subscribe({
          next: (data) => {
            this.ClientByOfficer = data;
            this.ClientByOfficer.forEach((x) => (x.isCheck = false));
            this.showLoader = false;
            this.isUpdating = true;
          },
          error: (err) => {
            console.log(err);
            this.showLoader = false;
          },
        });
      this.OfficerActiveModelResponse =
        await this.ReferencesService.GetOfficersWithOutOld(
          this.filterForm.value.old
        );
    } else {
      this.alertServices.showAlertError("يجب ادخال جميع البيانات", false);
    }
  }
  paging() {
    this.resultsCount = this.pagingService.totalCount;
    return this.pagingService.Paging(this.ClientByOfficer, this.page);
  }
  get isAllSelected(): boolean {
    return this.ClientByOfficer.every((x) => x.isCheck);
  }
  changePage(newPage: number): void {
    this.page = newPage;
  }
  onCheckboxMasterChange(event: any) {
    if (event.target.checked) {
      this.ClientByOfficer.forEach(
        (client) => (client.isCheck = event.target.checked)
      );
    } else {
      if (this.isAllSelected) {
        this.ClientByOfficer.forEach(
          (client) => (client.isCheck = event.target.checked)
        );
      }
    }
  }
  onCheckboxChange(event: any, client: any, index: any) {
    this.ClientByOfficer[index + this.pageSize * (this.page - 1)].isCheck =
      event.target.checked;
  }
  sortingTable(data: any, param: string) {
    this.sortingService.sortByParameter(data, param);
    this.sortingIconClass =
      this.sortingService.sortOrder === "asc"
        ? "arrow-down-outline"
        : "arrow-up-outline";
    this.sortingIconParam = param;
  }
  async UpdateOfficer() {
    if (this.OfficerForm.valid) {
      if (await this.alertService.SaveAlert()) {
        let clients = this.ClientByOfficer.filter((x) => x.isCheck === true);
        if (clients.length > 0) {
          this.showLoader = true;
          this.http
            .post(this.env.API_URL + `api/Officer/GetUpdateOfficerForClient`, {
              officer_key: this.OfficerForm.value.OfficerAllActive.toString(),
              client_key: clients.map((x) => x.client_key.toString()),
            })
            .subscribe({
              next: (data) => {
                this.clearForms();
                this.showLoader = false;
                this.alertService.showAlertConfirm("تم تغير المندوب ", true);
              },
              error: (err) => {
                this.alertService.showAlertError(err.error, false);
                this.showLoader = false;
              },
            });
        } else {
          this.alertService.showAlertError("لم يتم اختيار عميل", false);
        }
      }
    } else {
      this.alertService.showAlertError("لم يتم اختيار مندوب جديد", false);
    }
  }
  clearForms() {
    this.isUpdating = false;
  }
}
